constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k02887Custom {
public:
    __aicore__ inline KernelCa6k02887Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR bias, GM_ADDR y,
